#include <stdio.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int sorted=1; long long prev,cur;
        if(N>0){
            scanf("%lld",&prev);
            for(int i=1;i<N;i++){
                scanf("%lld",&cur);
                if(prev>cur) sorted=0;
                prev=cur;
            }
        }
        printf(sorted?"YES\n":"NO\n");
    }
    return 0;
}

